esqlQuery.esql:
TS metrics-mongodbreceiver.otel-default
// Scope to MongoDB OTel metrics
| WHERE data_stream.dataset == "mongodbreceiver.otel"
| WHERE metrics.mongodb.cursor.count IS NOT NULL
// Current open cursor count (gauge)
| STATS cursors = MAX(LAST_OVER_TIME(metrics.mongodb.cursor.count)) BY resource.attributes.server.address
// Alert when cursor count exceeds threshold (possible cursor leak; adjust 1000 for your workload)
| WHERE cursors > 1000
| SORT cursors DESC
| LIMIT 20
